// Linear interpolation of L, M, S at a fractional age within a stratum's tabulated
// range. Returns null when the age is outside [first, last] tabulated age so the
// caller can surface an out-of-domain message rather than extrapolate.
export function interpLMS(stratum, age) {
  if (!stratum || typeof stratum !== 'object' || !Array.isArray(stratum.age) || stratum.age.length === 0) return null;
  if (!Number.isFinite(age)) return null;
  const a = stratum.age;
  if (age < a[0] || age > a[a.length - 1]) return null;
  // exact / bracket search (ages are monotonically increasing)
  let hi = 1;
  while (hi < a.length && a[hi] < age) hi++;
  if (hi >= a.length) hi = a.length - 1;
  const lo = hi - 1;
  const span = a[hi] - a[lo];
  const t = span === 0 ? 0 : (age - a[lo]) / span;
  const lerp = (x, y) => x + (y - x) * t;
  return { L: lerp(stratum.L[lo], stratum.L[hi]), M: lerp(stratum.M[lo], stratum.M[hi]), S: lerp(stratum.S[lo], stratum.S[hi]) };
}

// LMS -> z-score: z = ((X/M)^L - 1) / (L*S), with the L -> 0 limit z = ln(X/M)/S.
// Guards M>0, S>0, X>0; returns null otherwise (never NaN/Infinity to the caller).
export function lmsToZ(L, M, S, X) {
  if (!Number.isFinite(L) || !Number.isFinite(M) || !Number.isFinite(S) || !Number.isFinite(X)) return null;
  if (M <= 0 || S <= 0 || X <= 0) return null;
  const ratio = X / M;
  const z = Math.abs(L) < 1e-7 ? Math.log(ratio) / S : (Math.pow(ratio, L) - 1) / (L * S);
  return Number.isFinite(z) ? z : null;
}
